/**
 * @method void setLocale(string $locale)
 */


/**
 * Base presenter for all application presenters.
 */
abstract class BasePresenter extends Nette\Application\UI\Presenter
{
    /** @persistent */
    public $locale;
    public $languages;

    // FORMS
    protected $subscribeForm;
    protected $contactForm;
    protected $contactFormSentData;

    // CONFIGS
    protected $applicationConfig;

    // SERVICES & MODELS
    //protected $translator;
    protected $detect;
    public $fastSpringModel;

    // OTHER
    protected $productCode;
    protected $pageType;
    public $customPageName; //used in contact form, as source page identification in mails/pushovers notifications for dynamicaly generated pages (such as news detail)

    //CONST
    const STATS_COOKIE = 'withdraw_statistic_cookie';

    public function __construct(SubscribeForm $subscribeForm, Translator $translator, ApplicationConfig $applicationConfig, ContactForm $contactForm)
    {
        $this->subscribeForm = $subscribeForm;
        $this->translator = $translator;
        $this->contactForm = $contactForm;
        $this->applicationConfig = $applicationConfig;
        $this->detect = new \Mobile_Detect();
    }

    public $httpRequest;

    public function injectRequest(Nette\Http\Request $httpRequest): void
    {
        $this->httpRequest = $httpRequest;
    }

    public $httpResponse;

    public function injectResponse(Nette\Http\Response $httpResponse): void
    {
        $this->httpResponse = $httpResponse;
    }

    /** @var \App\Service\Translator */
    private $translatorService;

    public function injectTranslator(\App\Service\Translator $translatorService): void
    {
        $this->translatorService = $translatorService;
    }

    public function injectFastSpringModel(FastSpringModel $fastSpringModel): void
    {
        $this->fastSpringModel = $fastSpringModel;
    }


    /** @var Contributte\Translation\Translator @inject */
    public $translator;

     /** @var Contributte\Translation\Translator @inject */
    public $translatorRouterResolver;

    public function handleChangeLocale(string $locale): void
    {
        $this->translatorRouterResolver->setLocale($locale);
        $this->redirect('this');
    }


    protected function beforeRender()
    {
        parent::beforeRender(); // TODO: Change the autogenerated stub
        $this->setAffiliateCookie();

        $this->manageFirstVisitCookie();

        $this->template->appConfig = $this->applicationConfig->getConfig();
        $this->template->cookie = [
            'name' => self::STATS_COOKIE,
            'value' => $this->httpRequest->getCookie(self::STATS_COOKIE),
        ];

        $this->template->detect = array(
            "platformDevice" => $this->detect->isMobile() ? ($this->detect->isTablet() ? 'tablet' : 'phone') : 'desktop',
            "isIE" => $this->detect->version('IE') ? 'true' : 'false',
            "isEdge" => $this->detect->version('Edge') ? 'true' : 'false',
            "isChrome" => 'false',
            "isSafari" => 'false',
            "isFirefox" => $this->detect->version('Firefox') ? 'true' : 'false',
        );

        if (stripos($this->detect->getUserAgent(), 'Chrome') !== false) {
            $this->template->detect["isChrome"] = 'true';
        } elseif (stripos($this->detect->getUserAgent(), 'Safari') !== false) {
            $this->template->detect["isSafari"] = 'true';
        }

        $this->template->addFilter('genericFormatDate', function ($date) {
            $dt = new DateTime($date);
            return $dt->format('F j, Y'); 
        });


        $languages = $this->translatorService->getAvailableLanguages();
        $languages = array_values(array_diff($languages, [$this->locale]));
        $this->template->locale = $this->locale;
        $this->template->alternativeLang = $languages[0];
        $this->template->isTranslated = $this->isPageTranslated();
    }

    private function manageFirstVisitCookie()
    {
        $cookieName = $this->applicationConfig->getConfig()["first_visit_cookie_name"];
        if ($this->httpRequest->getCookie($cookieName) === null) {
            $this->httpResponse->setCookie($cookieName, date("Y-m-d H:i:s"), '1 year', '/');
        }
    }

    private function setAffiliateCookie()
    {
        $cookieConsentRaw = $this->httpRequest->getCookie("cc_cookie");

        $allowSetAffiliateCookies = true;
        if ($cookieConsentRaw !== null) {
            $cookieConsent = json_decode($cookieConsentRaw, true);
            if (!in_array("marketing", $cookieConsent["level"])) {
                $allowSetAffiliateCookies = false;
            }
        }

        if ($allowSetAffiliateCookies === true) {
            $get['affiliate'] = $this->httpRequest->getQuery('affiliate');
            $get['affiliateid'] = $this->httpRequest->getQuery('affiliateid');
            if (isset($get['affiliate'])) {
                $this->httpResponse->setCookie($this->fastSpringModel->getConfig()["affiliate_cookie"], $get['affiliate'], '24 hours', '/');
            }
            if (isset($get['affiliateid'])) {
                $this->httpResponse->setCookie($this->fastSpringModel->getConfig()["affiliate_id_cookie"], $get['affiliateid'], '24 hours', '/');
            }
        }
    }

    private function isPageTranslated()
    {
        $pageTranslations = $this->translatorService->getPageTranslations($this->presenter->getName(), $this->presenter->getAction());

        if ($pageTranslations !== false && in_array($this->locale, $pageTranslations)) {
            $isTranslated = true;
        } else {
            if ($pageTranslations === false && $this->locale === $this->translatorService->getDefaultLang()) {
                $isTranslated = true;
            } else {
                $isTranslated = false;
            }
        }
        return $isTranslated;
    }

    protected function createComponentSubscribeNewsForm()
    {
        $form = $this->subscribeForm->create();

        /** @var \Nette\Forms\Control\TextInput $formListId */
        $formListId = $form['listId'];
        $formListId->setDefaultValue($this->subscribeForm->mailChimpModel->config["lists"]["24UGENERIC_" . strtoupper($this->locale)]["id"]);

        $listTag = $this->subscribeForm->getListTag();
        if (empty($listTag)) {
            $this->subscribeForm->setListTag($this->presenter->getName());
        }


        $form->onSuccess[] = function () {
            $this->template->resultType = (in_array($this->subscribeForm->getResult(), [SubscribeForm::RESULT_USER_RESUBSCRIBE, SubscribeForm::RESULT_NEW_USER]) ? "send_email" : "no_send_email");
            $this->template->snFormSuccess = true;
        };

        $this->redrawControl('snForm');


        return $form;
    }

    protected function createComponentAdvertismenSubscribeNewsForm()
    {
        $form = $this->subscribeForm->create();

              
        /** @var \Nette\Forms\Controls\TextInput $name */
        $name = $form['name'];
        $name->setRequired($this->translator->translate(SubscribeForm::TRANSLATE_PATH . "items.name.validation.required"));

        /** @var \Nette\Forms\Controls\TextInput $surname */
        $surname = $form['surname'];
        $surname->setRequired($this->translator->translate(SubscribeForm::TRANSLATE_PATH . "items.surname.validation.required"));

        /** @var \Nette\Forms\Controls\TextInput $listId */
        $listId = $form['listId'];
        $listId->setDefaultValue($this->subscribeForm->mailChimpModel->config["lists"]["24UGENERIC_" . strtoupper($this->locale)]["id"]);

        $listTag = $this->subscribeForm->getListTag();
        if (empty($listTag)) {
            $this->subscribeForm->setListTag($this->presenter->getName());
        }


        $form->onSuccess[] = function () {
            $this->template->resultType = (in_array($this->subscribeForm->getResult(), [SubscribeForm::RESULT_USER_RESUBSCRIBE, SubscribeForm::RESULT_NEW_USER]) ? "send_email" : "no_send_email");
            $this->template->asnFormSuccess = true;
        };

        $this->redrawControl('asnForm');


        return $form;
    }


    public function timezones()
    {
        $result = array();

        // only process geographical timezones

        foreach (preg_grep('~^(?:A(?:frica|merica|ntarctica|rctic|tlantic|sia|ustralia)|Europe|Indian|Pacific)/~', timezone_identifiers_list()) as $timezone) {
            if (is_object($timezone = new \DateTimeZone($timezone)) === true) {
                $currentTimeZoneTime = new \DateTime();
                $currentTimeZoneTime->setTimezone($timezone);
                $offset = $currentTimeZoneTime->format("Z") / 3600;
                $result[str_replace(".", ",", $offset)][] = preg_replace(array('~^.*/([^/]+)$~', '~_~'), array('$1', ' '), $timezone->getName());
            }
        }


        ksort($result);

        $response = [];

        foreach ($result as $offset => $timezones) {
            $offsetNumber = (str_replace(",", ".", $offset) * 1);

            $formatedOffset = $offset;
            if (is_float($offsetNumber)) {
                list($hoursInt, $minutesDecimal) = explode(".", $offsetNumber);

                $minutes = 60 * (("0." . $minutesDecimal) * 1);
                $formatedOffset = $hoursInt . ":" . $minutes;
            } else {
                $formatedOffset = $offsetNumber . ":00";
            }


            $utcName = "(UTC " . ($offset >= 0 ? "+" . $formatedOffset : $formatedOffset) . ")";
            $response[$utcName] = $timezones;

            //$result[$zone] = preg_replace(array('~^.*/([^/]+)$~', '~_~'), array('$1', ' '), $value); // "humanize" city names
            /*
                        if (array_key_exists(1, $offset = explode('|', $key)) === true) // "humanize" the offset
                        {
                            $offset = str_replace(' +00:00', '', sprintf('(UTC %+03d:%02u)', $offset[1] / 3600, abs($offset[1]) % 3600 / 60));
                        }

                        //$result[$zone] = array_slice($result[$zone], 0, 5);
                        if (asort($result[$zone]) === true) // sort city names
                        {
                            $result2[$offset][] = trim(sprintf('%s', implode(', ', $result[$zone])));

                        }*/
        }

        $output = [];
        $timezonesOnRow = 8;
        foreach ($response as $utc => $timezones) {
            $timezones = array_chunk($timezones, $timezonesOnRow);

            foreach ($timezones as $timezoneGroupNumber => $timezoneGroup) {
                $output[$timezoneGroupNumber . "||" . $utc] = $utc . " - " . implode(", ", $timezoneGroup);
            }
        }

        return $output;
    }

    public
    function addTimezones(
        $form
    ) {
        $form->addSelect("timezones", $label = null, $this->timezones());

        return $form;
    }

