    }

    protected function createComponentCreateFooterContactForm()
    {
        $form = $this->contactForm->create();

        if (isset($this->customPageName)) {
            $this->contactForm->setCurrentPage($this->presenter->getName() . ' [' . $this->customPageName . ']');
        } else {
            $this->contactForm->setCurrentPage($this->presenter->getName());
        }

         /** @var \Nette\Forms\Controls\TextInput $formType */
        $formType = $form["type"];

        /** @var \Nette\Forms\Controls\TextInput $formName */
        $formName = $form["name"];

        /** @var \Nette\Forms\Controls\TextInput $formEmail */
        $formEmail = $form["email"];

        /** @var \Nette\Forms\Controls\TextArea $formMessage */
        $formMessage = $form["message"];

        $formType->setDefaultValue("footer");

        $formName->setRequired($this->translator->translate(ContactForm::TRANSLATE_PATH . "items.name.validation.required"));
        $formEmail->setRequired($this->translator->translate(ContactForm::TRANSLATE_PATH . "items.email.validation.required"));
        $formMessage->setRequired($this->translator->translate(ContactForm::TRANSLATE_PATH . "items.message.validation.required"));

        $c1 = date('j') + 3;
        $c2 = date('N') + 2;
        $s = $c1 + $c2;

        $form->addText('spamSecureSum', sprintf('Sum the numbers %s+%s', $c1, $c2))
            ->setHtmlAttribute("placeholder", sprintf('Sum the numbers %s+%s', $c1, $c2))
            ->setHtmlAttribute("id", "frm-ft-spamSecureSum")
            ->setHtmlAttribute("class", "frm-ft-spamSecureSum")
            ->setRequired('Unknown error, please refresh the page')
            ->addRule(Form::Equal, 'Unknown error, please refresh the page', $s);
        $form->addHidden('c1', $c1)
            ->setHtmlAttribute("id", "frm-ft-c1");
        $form->addHidden('c2', $c2)
            ->setHtmlAttribute("id", "frm-ft-c2");
        $form->addHidden('formIdent');

        unset($form['number']);
        unset($form['topic']);
        unset($form['predata']);

        $form->onSuccess[] = function ($form) {
            if ($form->getValues()['formIdent'] == 'popup') {
                $this->template->footerContactFormPopupSuccess = true;
            } else {
                $this->template->footerContactFormSuccess = true;
            }
            //$this->template->footerContactFormSuccess = true;
            $this->setContactFormSentData($form->getValues());
        };

        $this->redrawControl('footerContactForm');
        $this->redrawControl('footerContactPopupForm');

        return $form;
    }

    /**
     * @param mixed $contactFormSentData
     */
    public function setContactFormSentData($contactFormSentData)
    {
        $this->contactFormSentData = $contactFormSentData;
    }

    /**
     * @return mixed
     */
    public function getContactFormSentData()
    {
        return $this->contactFormSentData;
    }
